/* eslint-disable */
// 替换逻辑
function replacePunctuationInBody(text) {
  // 1. 保护 HTML 标签，避免替换标签内的标点（如 style="color: #xxx;"）
  var protectedTags = [];
  var result = text.replace(/<[^>]+>/g, function(tag) {
    protectedTags.push(tag);
    return '\x00TAG' + (protectedTags.length - 1) + '\x00';
  });
  // 2. 替换标点
  result = result
    .replace(/\.\.\./g, '……').replace(/…+/g, '……')
    .replace(/,/g, '，')
    .replace(/!/g, '！')
    .replace(/\?/g, '？')
    .replace(/:/g, '：')
    .replace(/;/g, '；');
  // 3. 恢复 HTML 标签
  result = result.replace(/\x00TAG(\d+)\x00/g, function(_, idx) {
    return protectedTags[parseInt(idx)];
  });
  return result;
}

function replacePunctuationInContent(text) {
  return text.replace(
    /(<content>\s*\n*)([\s\S]*?)(\n*\s*<\/content>)/g,
    function(_full, prefix, body, suffix) {
      return prefix + replacePunctuationInBody(body) + suffix;
    }
  );
}

// 单条消息处理
function processMessageText(original) {
  var replaced = replacePunctuationInContent(original);
  return replaced !== original ? replaced : null;
}

// 批量扫描所有历史楼层
async function scanAllMessages() {
  console.info('[内容标点替换] 开始扫描所有历史楼层...');
  var allMessages = getChatMessages('0-{{lastMessageId}}');
  if (!allMessages || allMessages.length === 0) {
    console.info('[内容标点替换] 聊天中无消息，跳过扫描');
    return;
  }
  var toUpdate = [];
  for (var i = 0; i < allMessages.length; i++) {
    var msg = allMessages[i];
    if (msg.role !== 'assistant') continue;
    if (!msg.message) continue;
    var replaced = processMessageText(msg.message);
    if (replaced) toUpdate.push({ message_id: msg.message_id, message: replaced });
  }
  if (toUpdate.length === 0) {
    console.info('[内容标点替换] 扫描完成，所有楼层无需修改');
    return;
  }
  console.info('[内容标点替换] 扫描完成，需修改 ' + toUpdate.length + ' 个楼层，正在写入...');
  for (var j = 0; j < toUpdate.length; j++) {
    await setChatMessages([toUpdate[j]], { refresh: 'none' });
  }
  await setChatMessages([{ message_id: toUpdate[0].message_id }], { refresh: 'all' });
  console.info('[内容标点替换] 历史楼层全部替换完成，共 ' + toUpdate.length + ' 条');
}

// 实时监听新消息
var isProcessing = false;
async function processLatestMessage() {
  if (isProcessing) return;
  isProcessing = true;
  try {
    await new Promise(function(r) { setTimeout(r, 300); });
    var messages = getChatMessages(-1);
    if (!messages || messages.length === 0) { isProcessing = false; return; }
    var msg = messages[0];
    if (msg.role !== 'assistant') { isProcessing = false; return; }
    var original = msg.message;
    if (!original) { isProcessing = false; return; }
    var replaced = processMessageText(original);
    if (!replaced) { isProcessing = false; return; }
    await setChatMessages(
      [{ message_id: msg.message_id, message: replaced }],
      { refresh: 'affected' }
    );
    console.info('[内容标点替换] 已替换第 ' + msg.message_id + ' 楼');
  } catch (error) {
    console.error('[内容标点替换] 处理消息时出错:', error);
  } finally {
    isProcessing = false;
  }
}

// 启动
if (typeof tavern_events !== 'undefined') {
  setTimeout(function() { scanAllMessages(); }, 500);
  if (tavern_events.GENERATION_ENDED) {
    eventOn(tavern_events.GENERATION_ENDED, function() { processLatestMessage(); });
    console.info('[内容标点替换] 已注册 GENERATION_ENDED 监听器');
  } else if (tavern_events.MESSAGE_RECEIVED) {
    eventOn(tavern_events.MESSAGE_RECEIVED, function() { processLatestMessage(); });
    console.info('[内容标点替换] 已注册 MESSAGE_RECEIVED 监听器（降级）');
  } else {
    console.warn('[内容标点替换] 无可用的消息事件');
  }
} else {
  console.warn('[内容标点替换] tavern_events 不可用');
}
